// Mapping pôle → couleur
const POLE_COLORS = {
  'SUP': '#6B7280',
  'DEV': '#3B82F6',
  'DATA': '#8B5CF6',
  'DESIGN': '#F472B6',
  'INFRA': '#F97316',
  'RH': '#14B8A6',
  'COMM': '#FACC15',
  'FINANCE': '#EF4444',
  'JURIDIQUE': '#A78BFA',
};

const projects = $input.all().map(item => {
  const d = item.json;

  // Nom du projet (aplati par n8n)
  const name = d.name || d.property_name || 'Sans nom';

  // Pôle code (formula → string ou array)
  const poleRaw = Array.isArray(d.property_p_le_code)
    ? d.property_p_le_code[0]
    : d.property_p_le_code;
  const pole = poleRaw || null;

  // État d'avancement (aplati en string)
  const status = d.property_tat_d_avancement || 'Pas commencé';
  const isActive = status !== 'Terminé' && status !== 'Annulé';

  // Code projet
  const codeProjet = d.property_code_projet || '';

  // Couleur basée sur le pôle
  const color = POLE_COLORS[(pole || '').toUpperCase()] || '#6B7280';

  // Nom affiché
  const displayName = codeProjet && name ? `${codeProjet} — ${name}` : name;

  return {
    externalSourceId: d.id,
    name: displayName,
    color,
    pole: pole || undefined,
    isActive,
  };
}).filter(p => p.name && p.name !== 'Sans nom');

return [{ json: { projects } }];
